  ('heelevel3-8b44517b-moex-00220', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-111-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '依司法院釋字第469號解釋，有關國家賠償之成立，下列敘述何者錯誤？', '["公務員依法對特定人民負有作為義務而已無不作為之裁量餘地，倘故意過失怠於執行職務時， 有國家賠償之適用", "公務員在裁量收縮至零之情況下違反法律規定，此違法不僅是客觀法秩序違反，容有公權利侵 害之可能", "透過新保護規範理論，得探究系爭規定是否於立法目的上有保護特定之當事人，以為其主張救 濟之依據", "國家賠償之請求權限於法律明確規定特定人享有向行政機關為一定作為之請求權者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "310", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
